        <div class="languageSwitcher">
            <?php if (function_exists('pll_the_languages')): ?>
                <?php
                $format_lang_label = static function (?string $slug): string {
                    $slug = strtolower((string) $slug);
                    $map = [
                        'uk' => 'UKR',
                        'en' => 'ENG',
                    ];

                    return $map[$slug] ?? strtoupper($slug);
                };
                $languages = pll_the_languages([
                    'raw' => 1,
                    'hide_if_empty' => 0,
                    'hide_if_no_translation' => 0,
                    'display_names_as' => 'slug',
                ]);
                $current_slug = function_exists('pll_current_language') ? pll_current_language('slug') : null;
                ?>
                <?php if (!empty($languages)): ?>
                    <button class="currentLanguage" type="button">
                        <span><?php echo esc_html($format_lang_label($current_slug ?? array_key_first($languages))); ?></span>
                        <ul class="languagesList">
                            <?php foreach ($languages as $language): ?>
                                <li class="<?php echo $language['current_lang'] ? 'is-active' : ''; ?>">
                                    <a href="<?php echo esc_url($language['url']); ?>">
                                        <?php echo esc_html($format_lang_label($language['slug'])); ?>
                                    </a>
                                </li>
                            <?php endforeach; ?>
                        </ul>
                    </button>
                <?php endif; ?>
            <?php endif; ?>
